{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "AI Control Evidence Manifest",
  "description": "Index of evidence artifacts for all AI system controls, keyed by control ID",
  "type": "object",
  "properties": {
    "manifest_version": { "type": "string", "example": "1.0.0" },
    "audit_period_start": { "type": "string", "format": "date" },
    "audit_period_end": { "type": "string", "format": "date" },
    "subject_system": { "type": "string", "example": "ai-chat-platform-prod" },
    "controls": {
      "type": "object",
      "additionalProperties": {
        "type": "object",
        "required": ["control_name", "control_type", "framework_criteria", "evidence"],
        "properties": {
          "control_name": { "type": "string" },
          "control_type": { "enum": ["preventive", "detective", "corrective", "directive"] },
          "framework_criteria": {
            "type": "object",
            "properties": {
              "soc2": { "type": "array", "items": { "type": "string" } },
              "iso42001": { "type": "array", "items": { "type": "string" } },
              "nist_ai_rmf": { "type": "array", "items": { "type": "string" } }
            }
          },
          "evidence": {
            "type": "array",
            "items": {
              "type": "object",
              "required": ["artifact_id", "type", "date", "location", "sha256"],
              "properties": {
                "artifact_id": { "type": "string" },
                "type": {
                  "enum": [
                    "automated_test_result",
                    "audit_log_export",
                    "walkthrough_record",
                    "policy_document",
                    "exception_report",
                    "remediation_record",
                    "third_party_report"
                  ]
                },
                "date": { "type": "string", "format": "date" },
                "location": { "type": "string", "description": "S3 URI or similar" },
                "sha256": { "type": "string" },
                "notes": { "type": "string" }
              }
            }
          }
        }
      }
    }
  }
}
